def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=np.float64)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
        else:
            ratio = item / capacity if capacity != 0 else np.inf
            if ratio > 2:
                score = 0
                for k in range(1, 6):
                    term = (ratio ** k) / (k ** 2)
                    score += term if k % 2 == 1 else -term
                priorities[i] = score + np.exp(-ratio)
            elif 1 < ratio <= 2:
                acc = 1.0
                for j in range(1, 4):
                    inner_sum = 0
                    for m in range(1, j+2):
                        inner_sum += (ratio / m) ** j
                    acc += np.log(inner_sum + 1)
                priorities[i] = acc
            elif ratio == 1:
                priorities[i] = 1.5
            elif 0 < ratio < 1:
                val = 0
                for p in range(1, 5):
                    val += ((1 - ratio) ** p) / (p + ratio)
                priorities[i] = -np.log(val + 1e-10) if val > 0 else 0
            elif ratio == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.nan
    return priorities
